/* Nested 6-byte-stride table lookup: entry = tbl60[tbl70 ? tbl70[i].h0 : i].
 * Merged: the v1==0 branch was splat-split off as game_libs_func_00053174
 * (UNSHARED); merged back (0x38 -> 0x50). MATCH (2026-07-08): 6-byte struct
 * array indexing gives the IXA same-reg sll/subu/sll chains; the load-bearing
 * detail is `(v1 + a1)->h0` (pointer-add deref) instead of `v1[a1].h0` — the
 * uadd form allocates the tbl60 base load as the FIRST temp (t6) and keeps
 * the lhu in t9, where the uixa array-index form numbers the index chain
 * t6-first and swaps the final addu operands (78% plateau). */
typedef struct { u16 h0, h1, h2; } Ent6_5313C;
typedef struct { char pad[0x60]; Ent6_5313C *tbl60; char pad2[0xC]; Ent6_5313C *tbl70; } Tbls_5313C;
Ent6_5313C *game_libs_func_0005313C(Tbls_5313C *a0, int a1) {
    Ent6_5313C *v1 = a0->tbl70;
    if (v1 != 0) {
        return &a0->tbl60[(v1 + a1)->h0];
    }
    return &a0->tbl60[a1];
}
